examples.solution:
def all_columns_valid(A_matrix):
    n_states = len(A_matrix[0])
    n_obs = len(A_matrix)
    for s in range(n_states):
        col_sum = sum(A_matrix[obs][s] for obs in range(n_obs))
        if abs(col_sum - 1.0) > 0.001:
            return False
    return True
